{
  "summary": "This paper proposes vote-k, a novel graph-based selective annotation method within a two-step framework combining selective annotation and prompt retrieval to improve annotation efficiency for in-context learning with large language models. Extensive experiments across diverse NLP tasks demonstrate that vote-k significantly improves few-shot ICL performance and stability while reducing annotation cost compared to random selection and finetuning baselines.",
  "strengths": [
    {
      "point": "Novel graph-based selective annotation method balancing diversity and representativeness",
      "evidence": "vote-k constructs a k-NN graph over unlabeled data and iteratively selects samples with high vote scores that discount neighbors of already selected samples, improving selection quality."
    },
    {
      "point": "Comprehensive empirical validation across 10 diverse NLP tasks and multiple LLM sizes",
      "evidence": "Experiments show consistent relative gains over random selection, reduced variance, and robustness under domain shift and different LLM scales."
    },
    {
      "point": "Demonstrated annotation cost reduction compared to finetuning",
      "evidence": "vote-k with 10-100× fewer annotated examples achieves similar or better performance than state-of-the-art finetuning methods."
    },
    {
      "point": "Practical framework combining selective annotation and similarity-based prompt retrieval",
      "evidence": "The two-step approach explicitly addresses annotation cost and retrieval quality, with results showing random retrieval fails to leverage selective annotation benefits."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient comparison and discussion relative to classical active learning methods",
      "evidence": "The paper includes facility location and diversity baselines but lacks detailed analysis of how vote-k fundamentally differs or improves upon prior selective sampling approaches."
    },
    {
      "point": "Lack of sensitivity analysis on hyperparameter k and embedding choices",
      "evidence": "No ablation studies on the impact of k in the k-NN graph or on using/fine-tuning different embedding models, which may affect robustness and generalizability."
    },
    {
      "point": "Limited evaluation against recent or sophisticated active learning baselines",
      "evidence": "Comparisons omit gradient-based influence methods or retrieval-augmented selection strategies tailored for LLMs."
    },
    {
      "point": "Missing statistical significance testing for reported gains",
      "evidence": "Results report average relative improvements and variance but do not include paired tests or confidence intervals to confirm robustness."
    },
    {
      "point": "Reproducibility concerns due to missing implementation and hyperparameter details",
      "evidence": "Details on graph construction, vote computation, confidence bucket settings, and LLM prompting parameters are insufficiently specified."
    },
    {
      "point": "Limited discussion on scalability to very large unlabeled pools",
      "evidence": "The computational cost of constructing and processing the k-NN graph for large datasets is not addressed."
    },
    {
      "point": "Unclear applicability beyond classification and structured prediction tasks",
      "evidence": "Experiments focus on classification and structured prediction; generation-heavy tasks like open-ended dialogue are not explored."
    },
    {
      "point": "Insufficient explanation of domain shift experiments and interaction with prompt retrieval",
      "evidence": "Details on domain shifts and retrieval strategies are limited, and no ablation on joint optimization of selection and retrieval is provided."
    }
  ],
  "questions": [
    {
      "question": "How sensitive is vote-k’s performance to the choice of k and embedding model?",
      "motivation": "Understanding sensitivity is critical for applying vote-k robustly across datasets and domains."
    },
    {
      "question": "Can vote-k scale efficiently to very large unlabeled pools common in real-world annotation scenarios?",
      "motivation": "Scalability affects practical applicability and adoption in large-scale annotation pipelines."
    },
    {
      "question": "How does vote-k perform on generation-heavy tasks where embedding similarity may not capture example diversity effectively?",
      "motivation": "Extending applicability beyond classification tasks would broaden the method’s impact."
    },
    {
      "question": "Would integrating more recent active learning or retrieval-augmented selection methods improve or complement vote-k?",
      "motivation": "Comparisons and potential hybridization with state-of-the-art methods could strengthen empirical claims."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
